import re
from decimal import Decimal, ROUND_HALF_UP
from typing import List, Dict, Any, Optional
from datetime import datetime
from enum import Enum

class UserRole(Enum):
    BASIC = "basic"
    PREMIUM = "premium"
    ENTERPRISE = "enterprise"

class PaymentStatus(Enum):
    PENDING = "pending"
    PROCESSING = "processing"
    COMPLETED = "completed"
    FAILED = "failed"
    REFUNDED = "refunded"

class PaymentValidationError(Exception):
    pass

class AuthorizationError(Exception):
    pass

class StateTransitionError(Exception):
    pass

def validate_user_role(user: Dict[str, Any]) -> UserRole:
    if not user or 'role' not in user:
        raise AuthorizationError("Invalid user object: missing role")
    
    if 'id' not in user or not user['id']:
        raise AuthorizationError("Invalid user object: missing user ID")
    
    role_str = user['role'].lower() if isinstance(user['role'], str) else None
    
    try:
        return UserRole(role_str)
    except ValueError:
        raise AuthorizationError(f"Invalid user role: {user['role']}")

def get_discount_percentage(role: UserRole) -> Decimal:
    discount_map = {
        UserRole.BASIC: Decimal('0'),
        UserRole.PREMIUM: Decimal('15'),
        UserRole.ENTERPRISE: Decimal('30')
    }
    return discount_map[role]

def validate_cart_items(cart_items: List[Dict[str, Any]]) -> None:
    if not cart_items:
        raise PaymentValidationError("Cart is empty")
    
    if not isinstance(cart_items, list):
        raise PaymentValidationError("Cart items must be a list")
    
    for idx, item in enumerate(cart_items):
        if not isinstance(item, dict):
            raise PaymentValidationError(f"Cart item {idx} is not a valid object")
        
        if 'price' not in item:
            raise PaymentValidationError(f"Cart item {idx} missing price")
        
        if 'quantity' not in item:
            raise PaymentValidationError(f"Cart item {idx} missing quantity")
        
        try:
            price = Decimal(str(item['price']))
            if price < 0:
                raise PaymentValidationError(f"Cart item {idx} has negative price")
        except (ValueError, TypeError):
            raise PaymentValidationError(f"Cart item {idx} has invalid price format")
        
        try:
            quantity = int(item['quantity'])
            if quantity <= 0:
                raise PaymentValidationError(f"Cart item {idx} has invalid quantity")
        except (ValueError, TypeError):
            raise PaymentValidationError(f"Cart item {idx} has invalid quantity format")

def calculate_cart_total(cart_items: List[Dict[str, Any]]) -> Decimal:
    total = Decimal('0')
    
    for item in cart_items:
        price = Decimal(str(item['price']))
        quantity = Decimal(str(item['quantity']))
        item_total = price * quantity
        total += item_total
    
    return total.quantize(Decimal('0.01'), rounding=ROUND_HALF_UP)

def apply_discount(amount: Decimal, discount_percentage: Decimal) -> Dict[str, Decimal]:
    discount_amount = (amount * discount_percentage / Decimal('100')).quantize(
        Decimal('0.01'), rounding=ROUND_HALF_UP
    )
    final_amount = amount - discount_amount
    
    return {
        'original_amount': amount,
        'discount_percentage': discount_percentage,
        'discount_amount': discount_amount,
        'final_amount': final_amount
    }

def validate_payment_details(payment_details: Dict[str, Any]) -> None:
    if not payment_details or not isinstance(payment_details, dict):
        raise PaymentValidationError("Invalid payment details")
    
    required_fields = ['payment_method', 'currency']
    for field in required_fields:
        if field not in payment_details:
            raise PaymentValidationError(f"Missing required payment field: {field}")
    
    valid_payment_methods = ['credit_card', 'debit_card', 'paypal', 'bank_transfer']
    if payment_details['payment_method'] not in valid_payment_methods:
        raise PaymentValidationError(f"Invalid payment method: {payment_details['payment_method']}")
    
    valid_currencies = ['USD', 'EUR', 'GBP', 'CAD']
    if payment_details['currency'] not in valid_currencies:
        raise PaymentValidationError(f"Invalid currency: {payment_details['currency']}")
    
    if payment_details['payment_method'] in ['credit_card', 'debit_card']:
        if 'card_number' not in payment_details:
            raise PaymentValidationError("Card number required for card payments")
        
        card_number = re.sub(r'\s+', '', str(payment_details['card_number']))
        if not re.match(r'^\d{13,19}$', card_number):
            raise PaymentValidationError("Invalid card number format")
        
        if 'cvv' not in payment_details:
            raise PaymentValidationError("CVV required for card payments")
        
        if not re.match(r'^\d{3,4}$', str(payment_details['cvv'])):
            raise PaymentValidationError("Invalid CVV format")

def validate_state_transition(current_state: Optional[PaymentStatus], new_state: PaymentStatus) -> None:
    valid_transitions = {
        None: [PaymentStatus.PENDING],
        PaymentStatus.PENDING: [PaymentStatus.PROCESSING, PaymentStatus.FAILED],
        PaymentStatus.PROCESSING: [PaymentStatus.COMPLETED, PaymentStatus.FAILED],
        PaymentStatus.COMPLETED: [PaymentStatus.REFUNDED],
        PaymentStatus.FAILED: [PaymentStatus.PENDING],
        PaymentStatus.REFUNDED: []
    }
    
    if current_state not in valid_transitions:
        raise StateTransitionError(f"Invalid current state: {current_state}")
    
    if new_state not in valid_transitions[current_state]:
        raise StateTransitionError(
            f"Invalid state transition from {current_state} to {new_state}"
        )

def authorize_payment_amount(user: Dict[str, Any], amount: Decimal) -> None:
    max_transaction_limits = {
        UserRole.BASIC: Decimal('1000.00'),
        UserRole.PREMIUM: Decimal('5000.00'),
        UserRole.ENTERPRISE: Decimal('50000.00')
    }
    
    user_role = validate_user_role(user)
    max_limit = max_transaction_limits[user_role]
    
    if amount > max_limit:
        raise AuthorizationError(
            f"Transaction amount ${amount} exceeds limit ${max_limit} for {user_role.value} users"
        )
    
    if amount <= 0:
        raise PaymentValidationError("Payment amount must be greater than zero")

def process_payment_transaction(
    payment_details: Dict[str, Any],
    amount: Decimal,
    user_id: Any
) -> Dict[str, Any]:
    transaction_id = f"TXN-{user_id}-{datetime.utcnow().timestamp()}"
    
    payment_result = {
        'transaction_id': transaction_id,
        'status': PaymentStatus.COMPLETED.value,
        'amount': float(amount),
        'currency': payment_details['currency'],
        'payment_method': payment_details['payment_method'],
        'timestamp': datetime.utcnow().isoformat(),
        'message': 'Payment processed successfully'
    }
    
    return payment_result

def process_payment(
    user: Dict[str, Any],
    cart_items: List[Dict[str, Any]],
    payment_details: Dict[str, Any],
    current_payment_state: Optional[PaymentStatus] = None
) -> Dict[str, Any]:
    try:
        validate_state_transition(current_payment_state, PaymentStatus.PENDING)
        
        user_role = validate_user_role(user)
        
        validate_cart_items(cart_items)
        
        validate_payment_details(payment_details)
        
        cart_total = calculate_cart_total(cart_items)
        
        discount_percentage = get_discount_percentage(user_role)
        
        pricing_details = apply_discount(cart_total, discount_percentage)
        
        final_amount = pricing_details['final_amount']
        
        authorize_payment_amount(user, final_amount)
        
        validate_state_transition(PaymentStatus.PENDING, PaymentStatus.PROCESSING)
        
        payment_result = process_payment_transaction(
            payment_details,
            final_amount,
            user['id']
        )
        
        validate_state_transition(PaymentStatus.PROCESSING, PaymentStatus.COMPLETED)
        
        return {
            'success': True,
            'user_id': user['id'],
            'user_role': user_role.value,
            'cart_total': float(pricing_details['original_amount']),
            'discount_percentage': float(pricing_details['discount_percentage']),
            'discount_amount': float(pricing_details['discount_amount']),
            'final_amount': float(pricing_details['final_amount']),
            'payment_status': PaymentStatus.COMPLETED.value,
            'transaction': payment_result,
            'processed_at': datetime.utcnow().isoformat()
        }
    
    except (PaymentValidationError, AuthorizationError, StateTransitionError) as e:
        if current_payment_state == PaymentStatus.PROCESSING:
            validate_state_transition(PaymentStatus.PROCESSING, PaymentStatus.FAILED)
        
        return {
            'success': False,
            'error': str(e),
            'error_type': type(e).__name__,
            'payment_status': PaymentStatus.FAILED.value,
            'timestamp': datetime.utcnow().isoformat()
        }
    
    except Exception as e:
        return {
            'success': False,
            'error': 'An unexpected error occurred during payment processing',
            'error_type': 'UnexpectedError',
            'payment_status': PaymentStatus.FAILED.value,
            'timestamp': datetime.utcnow().isoformat()
        }